import { useState } from "react";
import { useNavigate } from "react-router-dom";
import mockUrunListesi from "../mock/mockUrunListesi";
import { Urun } from "../types/Urun";

interface KategoriTipi {
  baslik: string;
  altKategoriler: string[];
}

const kategoriler: KategoriTipi[] = [
  {
    baslik: "Cep Telefonu-Aksesuar",
    altKategoriler: [
      "Apple Telefonlar",
      "Android Telefonlar",
      "Yapay Zeka (AI) Telefonlar",
      "Giyilebilir Teknolojiler",
      "Aksesuarlar",
      "Tuşlu Telefonlar",
      "Yenilenmiş Telefonlar",
      "5G Destekli Akıllı Telefonlar",
    ],
  },
  {
    baslik: "Bilgisayar-Tablet",
    altKategoriler: [
      "Masaüstü Bilgisayarlar",
      "Dizüstü Bilgisayarlar",
      "Tabletler",
      "Modem & Network Ürünleri",
      "Veri Depolama Ürünleri",
      "Bilgisayar Çevre Birimleri",
      "Tablet Aksesuarları",
    ],
  },
  {
    baslik: "Elektrikli Ev Aletleri",
    altKategoriler: ["Blender Setleri", "Süpürgeler", "Fritözler"],
  },
  {
    baslik: "Sağlık-Kişisel Bakım",
    altKategoriler: ["Elektrikli Diş Fırçaları", "Saç Kurutma Makineleri"],
  },
  {
    baslik: "Hobi-Oyun",
    altKategoriler: ["Oyun Konsolları", "Aksesuarlar"],
  },
  {
    baslik: "TV-Ses Sistemleri",
    altKategoriler: ["Smart TV", "Ev Sinema Sistemleri"],
  },
  {
    baslik: "Ev-Yaşam",
    altKategoriler: ["Scooterlar", "Küçük Ev Aletleri"],
  },
];

export default function Kategoriler() {
  const [acilan, setAcilan] = useState<string | null>(null);
  const navigate = useNavigate();

  return (
    <div className="flex gap-6 mt-4 relative overflow-x-auto whitespace-nowrap border-y py-2 bg-white z-40">
      {kategoriler.map((kat, i) => (
        <div
          key={i}
          className="relative group"
          onMouseEnter={() => setAcilan(kat.baslik)}
          onMouseLeave={() => setAcilan(null)}
        >
          <button className="font-semibold px-2 hover:text-yellow-600 transition">
            {kat.baslik}
          </button>

          {kat.altKategoriler.length > 0 && acilan === kat.baslik && (
            <div className="absolute left-0 top-full mt-2 w-full bg-white shadow-xl border-t p-6 z-50 grid grid-cols-4 gap-6">
              <div className="col-span-1">
                <ul className="text-sm text-gray-800 space-y-1">
                  {kat.altKategoriler.map((alt, j) => (
                    <li
                      key={j}
                      className="hover:text-blue-600 cursor-pointer"
                      onClick={() => navigate(`/kategori/${alt}`)}
                    >
                      {alt}
                    </li>
                  ))}
                </ul>
              </div>
              <div className="col-span-3 grid grid-cols-2 gap-4">
                {mockUrunListesi
                  .filter((u: Urun) =>
                    kat.altKategoriler.includes(u.altKategori || "")
                  )
                  .slice(0, 2)
                  .map((urun) => (
                    <div
                      key={urun.id}
                      className="border p-2 rounded shadow-sm hover:shadow-md transition cursor-pointer"
                      onClick={() => navigate(`/urun/${urun.id}`)}
                    >
                      <img src={urun.gorsel} alt={urun.ad} className="h-24 mx-auto" />
                      <p className="text-sm mt-2 text-center font-medium">
                        {urun.ad}
                      </p>
                      <p className="text-xs text-center text-gray-600">
                        {urun.fiyat.toLocaleString()} TL
                      </p>
                    </div>
                  ))}
              </div>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}
